const book: BibleBook = {
  id: 'hebrews',
  name: 'Hebreus',
  englishName: 'Hebrews',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'God, having in the past spoken to the fathers through the prophets at many times and in various ways,', pt: 'Havendo Deus antigamente falado muitas vezes, e de muitas maneiras, aos pais, pelos profetas,' },
      { v: 2, en: 'has at the end of these days spoken to us by his Son, whom he appointed heir of all things, through whom also he made the worlds.', pt: 'nestes últimos dias a nós nos falou pelo Filho, a quem constituiu herdeiro de todas as coisas, e por quem fez também o mundo;' },
      { v: 3, en: 'His Son is the radiance of his glory, the very image of his substance, and upholding all things by the word of his power, who, when he had by himself purified us of our sins, sat down on the right hand of the Majesty on high;', pt: 'sendo ele o resplendor da sua glória e a expressa imagem do seu Ser, e sustentando todas as coisas pela palavra do seu poder, havendo ele mesmo feito a purificação dos pecados, assentou-se à direita da Majestade nas alturas,' },
      { v: 4, en: 'having become so much better than the angels, as he has inherited a more excellent name than they have.', pt: 'feito tanto mais excelente do que os anjos, quanto herdou mais excelente nome do que eles.' },
      { v: 5, en: 'For to which of the angels did he say at any time, “You are my Son. Today I have become your father?” and again, “I will be to him a Father, and he will be to me a Son?”', pt: 'Pois a qual dos anjos disse jamais: Tu és meu Filho, hoje te gerei? E outra vez: Eu lhe serei Pai, e ele me será Filho?' },
      { v: 6, en: 'When he again brings in the firstborn into the world he says, “Let all the angels of God worship him.”', pt: 'E outra vez, ao introduzir no mundo o primogênito, diz: E todos os anjos de Deus o adorem.' },
      { v: 7, en: 'Of the angels he says, “Who makes his angels winds, and his servants a flame of fire.”', pt: 'Ora, quanto aos anjos, diz: Quem de seus anjos faz ventos, e de seus ministros labaredas de fogo.' },
      { v: 8, en: 'But of the Son he says, “Your throne, O God, is forever and ever. The scepter of uprightness is the scepter of your Kingdom.', pt: 'Mas do Filho diz: O teu trono, ó Deus, subsiste pelos séculos dos séculos, e cetro de eqüidade é o cetro do teu reino.' },
      { v: 9, en: 'You have loved righteousness, and hated iniquity; therefore God, your God, has anointed you with the oil of gladness above your fellows.”', pt: 'Amaste a justiça e odiaste a iniqüidade; por isso Deus, o teu Deus, te ungiu com óleo de alegria, mais do que a teus companheiros;' },
      { v: 10, en: 'And, “You, Lord, in the beginning, laid the foundation of the earth. The heavens are the works of your hands.', pt: 'e: Tu, Senhor, no princípio fundaste a terra, e os céus são obras de tuas mãos;' },
      { v: 11, en: 'They will perish, but you continue. They all will grow old like a garment does.', pt: 'eles perecerão, mas tu permaneces; e todos eles, como roupa, envelhecerão,' },
      { v: 12, en: 'You will roll them up like a mantle, and they will be changed; but you are the same. Your years will not fail.”', pt: 'e qual um manto os enrolarás, e como roupa se mudarão; mas tu és o mesmo, e os teus anos não acabarão.' },
      { v: 13, en: 'But which of the angels has he told at any time, “Sit at my right hand, until I make your enemies the footstool of your feet?”', pt: 'Mas a qual dos anjos disse jamais: Assenta-te à minha direita até que eu ponha os teus inimigos por escabelo de teus pés?' },
      { v: 14, en: 'Aren’t they all serving spirits, sent out to do service for the sake of those who will inherit salvation?', pt: 'Não são todos eles espíritos ministradores, enviados para servir a favor dos que hão de herdar a salvação?' },
    ],
    2: [
      { v: 1, en: 'Therefore we ought to pay greater attention to the things that were heard, lest perhaps we drift away.', pt: 'Por isso convém atentarmos mais diligentemente para as coisas que ouvimos, para que em tempo algum nos desviemos delas.' },
      { v: 2, en: 'For if the word spoken through angels proved steadfast, and every transgression and disobedience received a just recompense;', pt: 'Pois se a palavra falada pelos anjos permaneceu firme, e toda transgressão e desobediência recebeu justa retribuição,' },
      { v: 3, en: 'how will we escape if we neglect so great a salvation—which at the first having been spoken through the Lord, was confirmed to us by those who heard;', pt: 'como escaparemos nós, se descuidarmos de tão grande salvação? A qual, tendo sido anunciada inicialmente pelo Senhor, foi- nos depois confirmada pelos que a ouviram:' },
      { v: 4, en: 'God also testifying with them, both by signs and wonders, by various works of power, and by gifts of the Holy Spirit, according to his own will?', pt: 'testificando Deus juntamente com eles, por sinais e prodígios, e por múltiplos milagres e dons do Espírito Santo, distribuídos segundo a sua vontade.' },
      { v: 5, en: 'For he didn’t subject the world to come, of which we speak, to angels.', pt: 'Porque não foi aos anjos que Deus sujeitou o mundo vindouro, de que falamos.' },
      { v: 6, en: 'But one has somewhere testified, saying, “What is man, that you think of him? Or the son of man, that you care for him?', pt: 'Mas em certo lugar testificou alguém dizendo: Que é o homem, para que te lembres dele? ou o filho do homem, para que o visites?' },
      { v: 7, en: 'You made him a little lower than the angels. You crowned him with glory and honor.', pt: 'Fizeste-o um pouco menor que os anjos, de glória e de honra o coroaste,' },
      { v: 8, en: 'You have put all things in subjection under his feet.” For in that he subjected all things to him, he left nothing that is not subject to him. But now we don’t see all things subjected to him, yet.', pt: 'todas as coisas lhe sujeitaste debaixo dos pés. Ora, visto que lhe sujeitou todas as coisas, nada deixou que não lhe fosse sujeito. Mas agora ainda não vemos todas as coisas sujeitas a ele;' },
      { v: 9, en: 'But we see him who has been made a little lower than the angels, Jesus, because of the suffering of death crowned with glory and honor, that by the grace of God he should taste of death for everyone.', pt: 'vemos, porém, aquele que foi feito um pouco menor que os anjos, Jesus, coroado de glória e honra, por causa da paixão da morte, para que, pela graça de Deus, provasse a morte por todos.' },
      { v: 10, en: 'For it became him, for whom are all things, and through whom are all things, in bringing many children to glory, to make the author of their salvation perfect through sufferings.', pt: 'Porque convinha que aquele, para quem são todas as coisas, e por meio de quem tudo existe, em trazendo muitos filhos à glória, aperfeiçoasse pelos sofrimentos o autor da salvação deles.' },
      { v: 11, en: 'For both he who sanctifies and those who are sanctified are all from one, for which cause he is not ashamed to call them brothers,', pt: 'Pois tanto o que santifica como os que são santificados, vêm todos de um só; por esta causa ele não se envergonha de lhes chamar irmãos,' },
      { v: 12, en: 'saying, “I will declare your name to my brothers. Among of the congregation I will sing your praise.”', pt: 'dizendo: Anunciarei o teu nome a meus irmãos, cantar-te-ei louvores no meio da congregação.' },
      { v: 13, en: 'Again, “I will put my trust in him.” Again, “Behold, here I am with the children whom God has given me.”', pt: 'E outra vez: Porei nele a minha confiança. E ainda: Eis-me aqui, e os filhos que Deus me deu.' },
      { v: 14, en: 'Since then the children have shared in flesh and blood, he also himself in the same way partook of the same, that through death he might bring to nothing him who had the power of death, that is, the devil,', pt: 'Portanto, visto como os filhos são participantes comuns de carne e sangue, também ele semelhantemente participou das mesmas coisas, para que pela morte derrotasse aquele que tinha o poder da morte, isto é, o Diabo;' },
      { v: 15, en: 'and might deliver all of them who through fear of death were all their lifetime subject to bondage.', pt: 'e livrasse todos aqueles que, com medo da morte, estavam por toda a vida sujeitos à escravidão.' },
      { v: 16, en: 'For most certainly, he doesn’t give help to angels, but he gives help to the offspring of Abraham.', pt: 'Pois, na verdade, não presta auxílio aos anjos, mas sim à descendência de Abraão.' },
      { v: 17, en: 'Therefore he was obligated in all things to be made like his brothers, that he might become a merciful and faithful high priest in things pertaining to God, to make atonement for the sins of the people.', pt: 'Pelo que convinha que em tudo fosse feito semelhante a seus irmãos, para se tornar um sumo sacerdote misericordioso e fiel nas coisas concernentes a Deus, a fim de fazer propiciação pelos pecados do povo.' },
      { v: 18, en: 'For in that he himself has suffered being tempted, he is able to help those who are tempted.', pt: 'Porque naquilo que ele mesmo, sendo tentado, padeceu, pode socorrer aos que são tentados.' },
    ],
    3: [
      { v: 1, en: 'Therefore, holy brothers, partakers of a heavenly calling, consider the Apostle and High Priest of our confession, Jesus;', pt: 'Pelo que, santos irmãos, participantes da vocação celestial, considerai o Apóstolo e Sumo Sacerdote da nossa confissão, Jesus,' },
      { v: 2, en: 'who was faithful to him who appointed him, as also was Moses in all his house.', pt: 'como ele foi fiel ao que o constituiu, assim como também o foi Moisés em toda a casa de Deus.' },
      { v: 3, en: 'For he has been counted worthy of more glory than Moses, because he who built the house has more honor than the house.', pt: 'Pois ele é tido por digno de tanto maior glória do que Moisés, quanto maior honra do que a casa tem aquele que a edificou.' },
      { v: 4, en: 'For every house is built by someone; but he who built all things is God.', pt: 'Porque toda casa é edificada por alguém, mas quem edificou todas as coisas é Deus.' },
      { v: 5, en: 'Moses indeed was faithful in all his house as a servant, for a testimony of those things which were afterward to be spoken,', pt: 'Moisés, na verdade, foi fiel em toda a casa de Deus, como servo, para testemunho das coisas que se haviam de anunciar;' },
      { v: 6, en: 'but Christ is faithful as a Son over his house; whose house we are, if we hold fast our confidence and the glorying of our hope firm to the end.', pt: 'mas Cristo o é como Filho sobre a casa de Deus; a qual casa somos nós, se tão-somente conservarmos firmes até o fim a nossa confiança e a glória da esperança.' },
      { v: 7, en: 'Therefore, even as the Holy Spirit says, “Today if you will hear his voice,', pt: 'Pelo que, como diz o Espírito Santo: Hoje, se ouvirdes a sua voz,' },
      { v: 8, en: 'don’t harden your hearts, as in the rebellion, like as in the day of the trial in the wilderness,', pt: 'não endureçais os vossos corações, como na provocação, no dia da tentação no deserto,' },
      { v: 9, en: 'where your fathers tested me by proving me, and saw my deeds for forty years.', pt: 'onde vossos pais me tentaram, pondo-me à prova, e viram por quarenta anos as minhas obras.' },
      { v: 10, en: 'Therefore I was displeased with that generation, and said, ‘They always err in their heart, but they didn’t know my ways;’', pt: 'Por isto me indignei contra essa geração, e disse: Estes sempre erram em seu coração, e não chegaram a conhecer os meus caminhos.' },
      { v: 11, en: 'as I swore in my wrath, ‘They will not enter into my rest.’”', pt: 'Assim jurei na minha ira: Não entrarão no meu descanso.' },
      { v: 12, en: 'Beware, brothers, lest perhaps there be in any one of you an evil heart of unbelief, in falling away from the living God;', pt: 'Vede, irmãos, que nunca se ache em qualquer de vós um perverso coração de incredulidade, para se apartar do Deus vivo;' },
      { v: 13, en: 'but exhort one another day by day, so long as it is called “today”; lest any one of you be hardened by the deceitfulness of sin.', pt: 'antes exortai-vos uns aos outros todos os dias, durante o tempo que se chama Hoje, para que nenhum de vós se endureça pelo engano do pecado;' },
      { v: 14, en: 'For we have become partakers of Christ, if we hold fast the beginning of our confidence firm to the end:', pt: 'porque nos temos tornado participantes de Cristo, se é que guardamos firme até o fim a nossa confiança inicial;' },
      { v: 15, en: 'while it is said, “Today if you will hear his voice, don’t harden your hearts, as in the rebellion.”', pt: 'enquanto se diz: Hoje, se ouvirdes a sua voz, não endureçais os vossos corações, como na provocação;' },
      { v: 16, en: 'For who, when they heard, rebelled? No, didn’t all those who came out of Egypt by Moses?', pt: 'pois quais os que, tendo-a ouvido, o provocaram? Não foram, porventura, todos os que saíram do Egito por meio de Moisés?' },
      { v: 17, en: 'With whom was he displeased forty years? Wasn’t it with those who sinned, whose bodies fell in the wilderness?', pt: 'E contra quem se indignou por quarenta anos? Não foi porventura contra os que pecaram, cujos corpos caíram no deserto?' },
      { v: 18, en: 'To whom did he swear that they wouldn’t enter into his rest, but to those who were disobedient?', pt: 'E a quem jurou que não entrariam no seu descanso, senão aos que foram desobedientes?' },
      { v: 19, en: 'We see that they were not able to enter in because of unbelief.', pt: 'E vemos que não puderam entrar por causa da incredulidade.' },
    ],
    4: [
      { v: 1, en: 'Let us fear therefore, lest perhaps anyone of you should seem to have come short of a promise of entering into his rest.', pt: 'Portanto, tendo-nos sido deixada a promessa de entrarmos no seu descanso, temamos não haja algum de vós que pareça ter falhado.' },
      { v: 2, en: 'For indeed we have had good news preached to us, even as they also did, but the word they heard didn’t profit them, because it wasn’t mixed with faith by those who heard.', pt: 'Porque também a nós foram pregadas as boas novas, assim como a eles; mas a palavra da pregação nada lhes aproveitou, porquanto não chegou a ser unida com a fé, naqueles que a ouviram.' },
      { v: 3, en: 'For we who have believed do enter into that rest, even as he has said, “As I swore in my wrath, they will not enter into my rest”; although the works were finished from the foundation of the world.', pt: 'Porque nós, os que temos crido, é que entramos no descanso, tal como disse: Assim jurei na minha ira: Não entrarão no meu descanso; embora as suas obras estivessem acabadas desde a fundação do mundo;' },
      { v: 4, en: 'For he has said this somewhere about the seventh day, “God rested on the seventh day from all his works”;', pt: 'pois em certo lugar disse ele assim do sétimo dia: E descansou Deus, no sétimo dia, de todas as suas obras;' },
      { v: 5, en: 'and in this place again, “They will not enter into my rest.”', pt: 'e outra vez, neste lugar: Não entrarão no meu descanso.' },
      { v: 6, en: 'Seeing therefore it remains that some should enter into it, and they to whom the good news was preached before failed to enter in because of disobedience,', pt: 'Visto, pois, restar que alguns entrem nele, e que aqueles a quem anteriormente foram pregadas as boas novas não entraram por causa da desobediência,' },
      { v: 7, en: 'he again defines a certain day, today, saying through David so long a time afterward (just as has been said), “Today if you will hear his voice, don’t harden your hearts.”', pt: 'determina outra vez um certo dia, Hoje, dizendo por Davi, depois de tanto tempo, como antes fora dito: Hoje, se ouvirdes a sua voz, não endureçais os vossos corações.' },
      { v: 8, en: 'For if Joshua had given them rest, he would not have spoken afterward of another day.', pt: 'Porque, se Josué lhes houvesse dado descanso, não teria falado depois disso de outro dia.' },
      { v: 9, en: 'There remains therefore a Sabbath rest for the people of God.', pt: 'Portanto resta ainda um repouso sabático para o povo de Deus.' },
      { v: 10, en: 'For he who has entered into his rest has himself also rested from his works, as God did from his.', pt: 'Pois aquele que entrou no descanso de Deus, esse também descansou de suas obras, assim como Deus das suas.' },
      { v: 11, en: 'Let us therefore give diligence to enter into that rest, lest anyone fall after the same example of disobedience.', pt: 'Ora, à vista disso, procuremos diligentemente entrar naquele descanso, para que ninguém caia no mesmo exemplo de desobediência.' },
      { v: 12, en: 'For the word of God is living and active, and sharper than any two-edged sword, piercing even to the dividing of soul and spirit, of both joints and marrow, and is able to discern the thoughts and intentions of the heart.', pt: 'Porque a palavra de Deus é viva e eficaz, e mais cortante do que qualquer espada de dois gumes, e penetra até a divisão de alma e espírito, e de juntas e medulas, e é apta para discernir os pensamentos e intenções do coração.' },
      { v: 13, en: 'There is no creature that is hidden from his sight, but all things are naked and laid open before the eyes of him to whom we must give an account.', pt: 'E não há criatura alguma encoberta diante dele; antes todas as coisas estão nuas e patentes aos olhos daquele a quem havemos de prestar contas.' },
      { v: 14, en: 'Having then a great high priest, who has passed through the heavens, Jesus, the Son of God, let us hold tightly to our confession.', pt: 'Tendo, portanto, um grande sumo sacerdote, Jesus, Filho de Deus, que penetrou os céus, retenhamos firmemente a nossa confissão.' },
      { v: 15, en: 'For we don’t have a high priest who can’t be touched with the feeling of our infirmities, but one who has been in all points tempted like we are, yet without sin.', pt: 'Porque não temos um sumo sacerdote que não possa compadecer- se das nossas fraquezas; porém um que, como nós, em tudo foi tentado, mas sem pecado.' },
      { v: 16, en: 'Let us therefore draw near with boldness to the throne of grace, that we may receive mercy, and may find grace for help in time of need.', pt: 'Cheguemo-nos, pois, confiadamente ao trono da graça, para que recebamos misericórdia e achemos graça, a fim de sermos socorridos no momento oportuno.' },
    ],
    5: [
      { v: 1, en: 'For every high priest, being taken from among men, is appointed for men in things pertaining to God, that he may offer both gifts and sacrifices for sins.', pt: 'Porque todo sumo sacerdote tomado dentre os homens é constituído a favor dos homens nas coisas concernentes a Deus, para que ofereça dons e sacrifícios pelos pecados,' },
      { v: 2, en: 'The high priest can deal gently with those who are ignorant and going astray, because he himself is also surrounded with weakness.', pt: 'podendo ele compadecer-se devidamente dos ignorantes e errados, porquanto também ele mesmo está rodeado de fraqueza.' },
      { v: 3, en: 'Because of this, he must offer sacrifices for sins for the people, as well as for himself.', pt: 'E por esta razão deve ele, tanto pelo povo como também por si mesmo, oferecer sacrifício pelos pecados.' },
      { v: 4, en: 'Nobody takes this honor on himself, but he is called by God, just like Aaron was.', pt: 'Ora, ninguém toma para si esta honra, senão quando é chamado por Deus, como o foi Arão.' },
      { v: 5, en: 'So also Christ didn’t glorify himself to be made a high priest, but it was he who said to him, “You are my Son. Today I have become your father.”', pt: 'assim também Cristo não se glorificou a si mesmo, para se fazer sumo sacerdote, mas o glorificou aquele que lhe disse: Tu és meu Filho, hoje te gerei;' },
      { v: 6, en: 'As he says also in another place, “You are a priest forever, after the order of Melchizedek.”', pt: 'como também em outro lugar diz: Tu és sacerdote para sempre, segundo a ordem de Melquisedeque.' },
      { v: 7, en: 'He, in the days of his flesh, having offered up prayers and petitions with strong crying and tears to him who was able to save him from death, and having been heard for his godly fear,', pt: 'O qual nos dias da sua carne, tendo oferecido, com grande clamor e lágrimas, orações e súplicas ao que podia livrar da morte, e tendo sido ouvido por causa da sua reverência,' },
      { v: 8, en: 'though he was a Son, yet learned obedience by the things which he suffered.', pt: 'ainda que era Filho, aprendeu a obediência por meio daquilo que sofreu;' },
      { v: 9, en: 'Having been made perfect, he became to all of those who obey him the author of eternal salvation,', pt: 'e, tendo sido aperfeiçoado, veio a ser autor de eterna salvação para todos os que lhe obedecem,' },
      { v: 10, en: 'named by God a high priest after the order of Melchizedek.', pt: 'sendo por Deus chamado sumo sacerdote, segundo a ordem de Melquisedeque.' },
      { v: 11, en: 'About him we have many words to say, and hard to interpret, seeing you have become dull of hearing.', pt: 'Sobre isso temos muito que dizer, mas de difícil interpretação, porquanto vos tornastes tardios em ouvir.' },
      { v: 12, en: 'For although by this time you should be teachers, you again need to have someone teach you the rudiments of the first principles of the revelations of God. You have come to need milk, and not solid food.', pt: 'Porque, devendo já ser mestres em razão do tempo, ainda necessitais de que se vos torne a ensinar os princípios elementares dos oráculos de Deus, e vos haveis feito tais que precisais de leite, e não de alimento sólido.' },
      { v: 13, en: 'For everyone who lives on milk is not experienced in the word of righteousness, for he is a baby.', pt: 'Ora, qualquer que se alimenta de leite é inexperiente na palavra da justiça, pois é criança;' },
      { v: 14, en: 'But solid food is for those who are full grown, who by reason of use have their senses exercised to discern good and evil.', pt: 'mas o alimento sólido é para os adultos, os quais têm, pela prática, as faculdades exercitadas para discernir tanto o bem como o mal.' },
    ],
    6: [
      { v: 1, en: 'Therefore leaving the teaching of the first principles of Christ, let us press on to perfection—not laying again a foundation of repentance from dead works, of faith toward God,', pt: 'Pelo que deixando os rudimentos da doutrina de Cristo, prossigamos até a perfeição, não lançando de novo o fundamento de arrependimento de obras mortas e de fé em Deus,' },
      { v: 2, en: 'of the teaching of baptisms, of laying on of hands, of resurrection of the dead, and of eternal judgment.', pt: 'e o ensino sobre batismos e imposição de mãos, e sobre ressurreição de mortos e juízo eterno.' },
      { v: 3, en: 'This will we do, if God permits.', pt: 'E isso faremos, se Deus o permitir.' },
      { v: 4, en: 'For concerning those who were once enlightened and tasted of the heavenly gift, and were made partakers of the Holy Spirit,', pt: 'Porque é impossível que os que uma vez foram iluminados, e provaram o dom celestial, e se fizeram participantes do Espírito Santo,' },
      { v: 5, en: 'and tasted the good word of God, and the powers of the age to come,', pt: 'e provaram a boa palavra de Deus, e os poderes do mundo vindouro,' },
      { v: 6, en: 'and then fell away, it is impossible to renew them again to repentance; seeing they crucify the Son of God for themselves again, and put him to open shame.', pt: 'e depois caíram, sejam outra vez renovados para arrependimento; visto que, quanto a eles, estão crucificando de novo o Filho de Deus, e o expondo ao vitupério.' },
      { v: 7, en: 'For the land which has drunk the rain that comes often on it, and produces a crop suitable for them for whose sake it is also tilled, receives blessing from God;', pt: 'Pois a terra que embebe a chuva, que cai muitas vezes sobre ela, e produz erva proveitosa para aqueles por quem é lavrada, recebe a bênção da parte de Deus;' },
      { v: 8, en: 'but if it bears thorns and thistles, it is rejected and near being cursed, whose end is to be burned.', pt: 'mas se produz espinhos e abrolhos, é rejeitada, e perto está da maldição; o seu fim é ser queimada.' },
      { v: 9, en: 'But, beloved, we are persuaded of better things for you, and things that accompany salvation, even though we speak like this.', pt: 'Mas de vós, ó amados, esperamos coisas melhores, e que acompanham a salvação, ainda que assim falamos.' },
      { v: 10, en: 'For God is not unrighteous, so as to forget your work and the labor of love which you showed toward his name, in that you served the saints, and still do serve them.', pt: 'Porque Deus não é injusto, para se esquecer da vossa obra, e do amor que para com o seu nome mostrastes, porquanto servistes aos santos, e ainda os servis.' },
      { v: 11, en: 'We desire that each one of you may show the same diligence to the fullness of hope even to the end,', pt: 'E desejamos que cada um de vós mostre o mesmo zelo até o fim, para completa certeza da esperança;' },
      { v: 12, en: 'that you won’t be sluggish, but imitators of those who through faith and perseverance inherited the promises.', pt: 'para que não vos torneis indolentes, mas sejais imitadores dos que pela fé e paciência herdam as promessas.' },
      { v: 13, en: 'For when God made a promise to Abraham, since he could swear by no one greater, he swore by himself,', pt: 'Porque, quando Deus fez a promessa a Abraão, visto que não tinha outro maior por quem jurar, jurou por si mesmo,' },
      { v: 14, en: 'saying, “Surely blessing I will bless you, and multiplying I will multiply you.”', pt: 'dizendo: Certamente te abençoarei, e grandemente te multiplicarei.' },
      { v: 15, en: 'Thus, having patiently endured, he obtained the promise.', pt: 'E assim, tendo Abraão esperado com paciência, alcançou a promessa.' },
      { v: 16, en: 'For men indeed swear by a greater one, and in every dispute of theirs the oath is final for confirmation.', pt: 'Pois os homens juram por quem é maior do que eles, e o juramento para confirmação é, para eles, o fim de toda contenda.' },
      { v: 17, en: 'In this way God, being determined to show more abundantly to the heirs of the promise the immutability of his counsel, interposed with an oath;', pt: 'assim que, querendo Deus mostrar mais abundantemente aos herdeiros da promessa a imutabilidade do seu conselho, se interpôs com juramento;' },
      { v: 18, en: 'that by two immutable things, in which it is impossible for God to lie, we may have a strong encouragement, who have fled for refuge to take hold of the hope set before us.', pt: 'para que por duas coisas imutáveis, nas quais é impossivel que Deus minta, tenhamos poderosa consolação, nós, os que nos refugiamos em lançar mão da esperança proposta;' },
      { v: 19, en: 'This hope we have as an anchor of the soul, a hope both sure and steadfast and entering into that which is within the veil;', pt: 'a qual temos como âncora da alma, segura e firme, e que penetra até o interior do véu;' },
      { v: 20, en: 'where as a forerunner Jesus entered for us, having become a high priest forever after the order of Melchizedek.', pt: 'aonde Jesus, como precursor, entrou por nós, feito sacerdote para sempre, segundo a ordem de Melquisedeque.' },
    ],
    7: [
      { v: 1, en: 'For this Melchizedek, king of Salem, priest of God Most High, who met Abraham returning from the slaughter of the kings and blessed him,', pt: 'Porque este Melquisedeque, rei de Salém, sacerdote do Deus Altíssimo, que saiu ao encontro de Abraão quando este regressava da matança dos reis, e o abençoou,' },
      { v: 2, en: 'to whom also Abraham divided a tenth part of all (being first, by interpretation, “king of righteousness”, and then also “king of Salem”, which means “king of peace”;', pt: 'a quem também Abraão separou o dízimo de tudo (sendo primeiramente, por interpretação do seu nome, rei de justiça, e depois também rei de Salém, que é rei de paz;' },
      { v: 3, en: 'without father, without mother, without genealogy, having neither beginning of days nor end of life, but made like the Son of God), remains a priest continually.', pt: 'sem pai, sem mãe, sem genealogia, não tendo princípio de dias nem fim de vida, mas feito semelhante ao Filho de Deus), permanece sacerdote para sempre.' },
      { v: 4, en: 'Now consider how great this man was, to whom even Abraham, the patriarch, gave a tenth out of the best plunder.', pt: 'Considerai, pois, quão grande era este, a quem até o patriarca Abraão deu o dízimo dentre os melhores despojos.' },
      { v: 5, en: 'They indeed of the sons of Levi who receive the priest’s office have a commandment to take tithes of the people according to the law, that is, of their brothers, though these have come out of the body of Abraham,', pt: 'E os que dentre os filhos de Levi recebem o sacerdócio têm ordem, segundo a lei, de tomar os dízimos do povo, isto é, de seus irmãos, ainda que estes também tenham saído dos lombos de Abraão;' },
      { v: 6, en: 'but he whose genealogy is not counted from them has accepted tithes from Abraham, and has blessed him who has the promises.', pt: 'mas aquele cuja genealogia não é contada entre eles, tomou dízimos de Abraão, e abençoou ao que tinha as promessas.' },
      { v: 7, en: 'But without any dispute the lesser is blessed by the greater.', pt: 'Ora, sem contradição alguma, o menor é abençoado pelo maior.' },
      { v: 8, en: 'Here people who die receive tithes, but there one receives tithes of whom it is testified that he lives.', pt: 'E aqui certamente recebem dízimos homens que morrem; ali, porém, os recebe aquele de quem se testifica que vive.' },
      { v: 9, en: 'We can say that through Abraham even Levi, who receives tithes, has paid tithes,', pt: 'E, por assim dizer, por meio de Abraão, até Levi, que recebe dízimos, pagou dízimos,' },
      { v: 10, en: 'for he was yet in the body of his father when Melchizedek met him.', pt: 'porquanto ele estava ainda nos lombos de seu pai quando Melquisedeque saiu ao encontro deste.' },
      { v: 11, en: 'Now if there were perfection through the Levitical priesthood (for under it the people have received the law), what further need was there for another priest to arise after the order of Melchizedek, and not be called after the order of Aaron?', pt: 'De sorte que, se a perfeição fosse pelo sacerdócio levítico (pois sob este o povo recebeu a lei), que necessidade havia ainda de que outro sacerdote se levantasse, segundo a ordem de Melquisedeque, e que não fosse contado segundo a ordem de Arão?' },
      { v: 12, en: 'For the priesthood being changed, there is of necessity a change made also in the law.', pt: 'Pois, mudando-se o sacerdócio, necessariamente se faz também mudança da lei.' },
      { v: 13, en: 'For he of whom these things are said belongs to another tribe, from which no one has officiated at the altar.', pt: 'Porque aquele, de quem estas coisas se dizem, pertence a outra tribo, da qual ninguém ainda serviu ao altar,' },
      { v: 14, en: 'For it is evident that our Lord has sprung out of Judah, about which tribe Moses spoke nothing concerning priesthood.', pt: 'visto ser manifesto que nosso Senhor procedeu de Judá, tribo da qual Moisés nada falou acerca de sacerdotes.' },
      { v: 15, en: 'This is yet more abundantly evident, if after the likeness of Melchizedek there arises another priest,', pt: 'E ainda muito mais manifesto é isto, se à semelhança de Melquisedeque se levanta outro sacerdote,' },
      { v: 16, en: 'who has been made, not after the law of a fleshly commandment, but after the power of an endless life:', pt: 'que não foi feito conforme a lei de um mandamento carnal, mas segundo o poder duma vida indissolúvel.' },
      { v: 17, en: 'for it is testified, “You are a priest forever, according to the order of Melchizedek.”', pt: 'Porque dele assim se testifica: Tu és sacerdote para sempre, segundo a ordem de Melquisedeque.' },
      { v: 18, en: 'For there is an annulling of a foregoing commandment because of its weakness and uselessness', pt: 'Pois, com efeito, o mandamento anterior é ab-rogado por causa da sua fraqueza e inutilidade' },
      { v: 19, en: '(for the law made nothing perfect), and a bringing in of a better hope, through which we draw near to God.', pt: '(pois a lei nenhuma coisa aperfeiçoou), e desta sorte é introduzida uma melhor esperança, pela qual nos aproximamos de Deus.' },
      { v: 20, en: 'Inasmuch as he was not made priest without the taking of an oath', pt: 'E visto como não foi sem prestar juramento (porque, na verdade, aqueles, sem juramento, foram feitos sacerdotes,' },
      { v: 21, en: '(for they indeed have been made priests without an oath), but he with an oath by him that says of him, “The Lord swore and will not change his mind, ‘You are a priest forever, according to the order of Melchizedek.’”', pt: 'mas este com juramento daquele que lhe disse: Jurou o Senhor, e não se arrependerá: Tu és sacerdote para sempre),' },
      { v: 22, en: 'By so much, Jesus has become the collateral of a better covenant.', pt: 'de tanto melhor pacto Jesus foi feito fiador.' },
      { v: 23, en: 'Many, indeed, have been made priests, because they are hindered from continuing by death.', pt: 'E, na verdade, aqueles foram feitos sacerdotes em grande número, porque pela morte foram impedidos de permanecer,' },
      { v: 24, en: 'But he, because he lives forever, has his priesthood unchangeable.', pt: 'mas este, porque permanece para sempre, tem o seu sacerdócio perpétuo.' },
      { v: 25, en: 'Therefore he is also able to save to the uttermost those who draw near to God through him, seeing that he lives forever to make intercession for them.', pt: 'Portanto, pode também salvar perfeitamente os que por ele se chegam a Deus, porquanto vive sempre para interceder por eles.' },
      { v: 26, en: 'For such a high priest was fitting for us: holy, guiltless, undefiled, separated from sinners, and made higher than the heavens;', pt: 'Porque nos convinha tal sumo sacerdote, santo, inocente, imaculado, separado dos pecadores, e feito mais sublime que os céus;' },
      { v: 27, en: 'who doesn’t need, like those high priests, to offer up sacrifices daily, first for his own sins, and then for the sins of the people. For he did this once for all, when he offered up himself.', pt: 'que não necessita, como os sumos sacerdotes, de oferecer cada dia sacrifícios, primeiramente por seus próprios pecados, e depois pelos do povo; porque isto fez ele, uma vez por todas, quando se ofereceu a si mesmo.' },
      { v: 28, en: 'For the law appoints men as high priests who have weakness, but the word of the oath which came after the law appoints a Son forever who has been perfected.', pt: 'Porque a lei constitui sumos sacerdotes a homens que têm fraquezas, mas a palavra do juramento, que veio depois da lei, constitui ao Filho, para sempre aperfeiçoado.' },
    ],
    8: [
      { v: 1, en: 'Now in the things which we are saying, the main point is this. We have such a high priest, who sat down on the right hand of the throne of the Majesty in the heavens,', pt: 'Ora, do que estamos dizendo, o ponto principal é este: Temos um sumo sacerdote tal, que se assentou nos céus à direita do trono da Majestade,' },
      { v: 2, en: 'a servant of the sanctuary, and of the true tabernacle, which the Lord pitched, not man.', pt: 'ministro do santuário, e do verdadeiro tabernáculo, que o Senhor fundou, e não o homem.' },
      { v: 3, en: 'For every high priest is appointed to offer both gifts and sacrifices. Therefore it is necessary that this high priest also have something to offer.', pt: 'Porque todo sumo sacerdote é constituído para oferecer dons e sacrifícios; pelo que era necessário que esse sumo sacerdote também tivesse alguma coisa que oferecer.' },
      { v: 4, en: 'For if he were on earth, he would not be a priest at all, seeing there are priests who offer the gifts according to the law;', pt: 'Ora, se ele estivesse na terra, nem seria sacerdote, havendo já os que oferecem dons segundo a lei,' },
      { v: 5, en: 'who serve a copy and shadow of the heavenly things, even as Moses was warned by God when he was about to make the tabernacle, for he said, “See, you shall make everything according to the pattern that was shown to you on the mountain.”', pt: 'os quais servem àquilo que é figura e sombra das coisas celestiais, como Moisés foi divinamente avisado, quando estava para construir o tabernáculo; porque lhe foi dito: Olha, faze conforme o modelo que no monte se te mostrou.' },
      { v: 6, en: 'But now he has obtained a more excellent ministry, by so much as he is also the mediator of a better covenant, which on better promises has been given as law.', pt: 'Mas agora alcançou ele ministério tanto mais excelente, quanto é mediador de um melhor pacto, o qual está firmado sobre melhores promessas.' },
      { v: 7, en: 'For if that first covenant had been faultless, then no place would have been sought for a second.', pt: 'Pois, se aquele primeiro fora sem defeito, nunca se teria buscado lugar para o segundo.' },
      { v: 8, en: 'For finding fault with them, he said, “Behold, the days come”, says the Lord, “that I will make a new covenant with the house of Israel and with the house of Judah;', pt: 'Porque repreendendo-os, diz: Eis que virão dias, diz o Senhor, em que estabelecerei com a casa de Israel e com a casa de Judá um novo pacto.' },
      { v: 9, en: 'not according to the covenant that I made with their fathers, in the day that I took them by the hand to lead them out of the land of Egypt; for they didn’t continue in my covenant, and I disregarded them,” says the Lord.', pt: 'Não segundo o pacto que fiz com seus pais no dia em que os tomei pela mão, para os tirar da terra do Egito; pois não permaneceram naquele meu pacto, e eu para eles não atentei, diz o Senhor.' },
      { v: 10, en: '“For this is the covenant that I will make with the house of Israel. After those days,” says the Lord; “I will put my laws into their mind, I will also write them on their heart. I will be their God, and they will be my people.', pt: 'Ora, este é o pacto que farei com a casa de Israel, depois daqueles dias, diz o Senhor; porei as minhas leis no seu entendimento, e em seu coração as escreverei; eu serei o seu Deus, e eles serão o meu povo;' },
      { v: 11, en: 'They will not teach every man his fellow citizen, and every man his brother, saying, ‘Know the Lord,’ for all will know me, from their least to their greatest.', pt: 'e não ensinará cada um ao seu concidadão, nem cada um ao seu irmão, dizendo: Conhece ao Senhor; porque todos me conhecerão, desde o menor deles até o maior.' },
      { v: 12, en: 'For I will be merciful to their unrighteousness. I will remember their sins and lawless deeds no more.”', pt: 'Porque serei misericordioso para com suas iniquidades, e de seus pecados não me lembrarei mais.' },
      { v: 13, en: 'In that he says, “A new covenant”, he has made the first old. But that which is becoming old and grows aged is near to vanishing away.', pt: 'Dizendo: Novo pacto, ele tornou antiquado o primeiro. E o que se torna antiquado e envelhece, perto está de desaparecer.' },
    ],
    9: [
      { v: 1, en: 'Now indeed even the first covenant had ordinances of divine service, and an earthly sanctuary.', pt: 'Ora, também o primeiro pacto tinha ordenanças de serviço sagrado, e um santuário terrestre.' },
      { v: 2, en: 'For a tabernacle was prepared. In the first part were the lamp stand, the table, and the show bread; which is called the Holy Place.', pt: 'Pois foi preparada uma tenda, a primeira, na qual estavam o candeeiro, e a mesa, e os pães da proposição; a essa se chama o santo lugar;' },
      { v: 3, en: 'After the second veil was the tabernacle which is called the Holy of Holies,', pt: 'mas depois do segundo véu estava a tenda que se chama o santo dos santos,' },
      { v: 4, en: 'having a golden altar of incense, and the ark of the covenant overlaid on all sides with gold, in which was a golden pot holding the manna, Aaron’s rod that budded, and the tablets of the covenant;', pt: 'que tinha o incensário de ouro, e a arca do pacto, toda coberta de ouro em redor; na qual estava um vaso de ouro, que continha o maná, e a vara de Arão, que tinha brotado, e as tábuas do pacto;' },
      { v: 5, en: 'and above it cherubim of glory overshadowing the mercy seat, of which things we can’t speak now in detail.', pt: 'e sobre a arca os querubins da glória, que cobriam o propiciatório; das quais coisas não falaremos agora particularmente.' },
      { v: 6, en: 'Now these things having been thus prepared, the priests go in continually into the first tabernacle, accomplishing the services,', pt: 'Ora, estando estas coisas assim preparadas, entram continuamente na primeira tenda os sacerdotes, celebrando os serviços sagrados;' },
      { v: 7, en: 'but into the second the high priest alone, once in the year, not without blood, which he offers for himself, and for the errors of the people.', pt: 'mas na segunda só o sumo sacerdote, uma vez por ano, não sem sangue, o qual ele oferece por si mesmo e pelos erros do povo;' },
      { v: 8, en: 'The Holy Spirit is indicating this, that the way into the Holy Place wasn’t yet revealed while the first tabernacle was still standing;', pt: 'dando o Espírito Santo a entender com isso, que o caminho do santuário não está descoberto, enquanto subsiste a primeira tenda,' },
      { v: 9, en: 'which is a symbol of the present age, where gifts and sacrifices are offered that are incapable, concerning the conscience, of making the worshiper perfect;', pt: 'que é uma parábola para o tempo presente, conforme a qual se oferecem tando dons como sacrifícios que, quanto à consciência, não podem aperfeiçoar aquele que presta o culto;' },
      { v: 10, en: 'being only (with meats and drinks and various washings) fleshly ordinances, imposed until a time of reformation.', pt: 'sendo somente, no tocante a comidas, e bebidas, e várias abluções, umas ordenanças da carne, impostas até um tempo de reforma.' },
      { v: 11, en: 'But Christ having come as a high priest of the coming good things, through the greater and more perfect tabernacle, not made with hands, that is to say, not of this creation,', pt: 'Mas Cristo, tendo vindo como sumo sacerdote dos bens já realizados, por meio do maior e mais perfeito tabernáculo (não feito por mãos, isto é, não desta criação),' },
      { v: 12, en: 'nor yet through the blood of goats and calves, but through his own blood, entered in once for all into the Holy Place, having obtained eternal redemption.', pt: 'e não pelo sangue de bodes e novilhos, mas por seu próprio sangue, entrou uma vez por todas no santo lugar, havendo obtido uma eterna redenção.' },
      { v: 13, en: 'For if the blood of goats and bulls, and the ashes of a heifer sprinkling those who have been defiled, sanctify to the cleanness of the flesh:', pt: 'Porque, se a aspersão do sangue de bodes e de touros, e das cinzas duma novilha santifica os contaminados, quanto à purificação da carne,' },
      { v: 14, en: 'how much more will the blood of Christ, who through the eternal Spirit offered himself without defect to God, cleanse your conscience from dead works to serve the living God?', pt: 'quanto mais o sangue de Cristo, que pelo Espírito eterno se ofereceu a si mesmo imaculado a Deus, purificará das obras mortas a vossa consciência, para servirdes ao Deus vivo?' },
      { v: 15, en: 'For this reason he is the mediator of a new covenant, since a death has occurred for the redemption of the transgressions that were under the first covenant, that those who have been called may receive the promise of the eternal inheritance.', pt: 'E por isso é mediador de um novo pacto, para que, intervindo a morte para remissão das transgressões cometidas debaixo do primeiro pacto, os chamados recebam a promessa da herança eterna.' },
      { v: 16, en: 'For where a last will and testament is, there must of necessity be the death of him who made it.', pt: 'Pois onde há testamento, necessário é que intervenha a morte do testador.' },
      { v: 17, en: 'For a will is in force where there has been death, for it is never in force while he who made it lives.', pt: 'Porque um testamento não tem torça senão pela morte, visto que nunca tem valor enquanto o testador vive.' },
      { v: 18, en: 'Therefore even the first covenant has not been dedicated without blood.', pt: 'Pelo que nem o primeiro pacto foi consagrado sem sangue;' },
      { v: 19, en: 'For when every commandment had been spoken by Moses to all the people according to the law, he took the blood of the calves and the goats, with water and scarlet wool and hyssop, and sprinkled both the book itself and all the people,', pt: 'porque, havendo Moisés anunciado a todo o povo todos os mandamentos segundo a lei, tomou o sangue dos novilhos e dos bodes, com água, lã purpúrea e hissopo e aspergiu tanto o próprio livro como todo o povo,' },
      { v: 20, en: 'saying, “This is the blood of the covenant which God has commanded you.”', pt: 'dizendo: este é o sangue do pacto que Deus ordenou para vós.' },
      { v: 21, en: 'Moreover he sprinkled the tabernacle and all the vessels of the ministry in the same way with the blood.', pt: 'Semelhantemente aspergiu com sangue também o tabernáculo e todos os vasos do serviço sagrado.' },
      { v: 22, en: 'According to the law, nearly everything is cleansed with blood, and apart from shedding of blood there is no remission.', pt: 'E quase todas as coisas, segundo a lei, se purificam com sangue; e sem derramamento de sangue não há remissão.' },
      { v: 23, en: 'It was necessary therefore that the copies of the things in the heavens should be cleansed with these; but the heavenly things themselves with better sacrifices than these.', pt: 'Era necessário, portanto, que as figuras das coisas que estão no céu fossem purificadas com tais sacrifícios, mas as próprias coisas celestiais com sacrifícios melhores do que estes.' },
      { v: 24, en: 'For Christ hasn’t entered into holy places made with hands, which are representations of the true, but into heaven itself, now to appear in the presence of God for us;', pt: 'Pois Cristo não entrou num santuário feito por mãos, figura do verdadeiro, mas no próprio céu, para agora comparecer por nós perante a face de Deus;' },
      { v: 25, en: 'nor yet that he should offer himself often, as the high priest enters into the holy place year by year with blood not his own,', pt: 'nem também para se oferecer muitas vezes, como o sumo sacerdote de ano em ano entra no santo lugar com sangue alheio;' },
      { v: 26, en: 'or else he must have suffered often since the foundation of the world. But now once at the end of the ages, he has been revealed to put away sin by the sacrifice of himself.', pt: 'doutra forma, necessário lhe fora padecer muitas vezes desde a fundação do mundo; mas agora, na consumação dos séculos, uma vez por todas se manifestou, para aniquilar o pecado pelo sacrifício de si mesmo.' },
      { v: 27, en: 'Inasmuch as it is appointed for men to die once, and after this, judgment,', pt: 'E, como aos homens está ordenado morrerem uma só vez, vindo depois o juízo,' },
      { v: 28, en: 'so Christ also, having been offered once to bear the sins of many, will appear a second time, without sin, to those who are eagerly waiting for him for salvation.', pt: 'assim também Cristo, oferecendo-se uma só vez para levar os pecados de muitos, aparecerá segunda vez, sem pecado, aos que o esperam para salvação.' },
    ],
    10: [
      { v: 1, en: 'For the law, having a shadow of the good to come, not the very image of the things, can never with the same sacrifices year by year, which they offer continually, make perfect those who draw near.', pt: 'Porque a lei, tendo a sombra dos bens futuros, e não a imagem exata das coisas, não pode nunca, pelos mesmos sacrifícios que continuamente se oferecem de ano em ano, aperfeiçoar os que se chegam a Deus.' },
      { v: 2, en: 'Or else wouldn’t they have ceased to be offered, because the worshipers, having been once cleansed, would have had no more consciousness of sins?', pt: 'Doutra maneira, não teriam deixado de ser oferecidos? pois tendo sido uma vez purificados os que prestavam o culto, nunca mais teriam consciência de pecado.' },
      { v: 3, en: 'But in those sacrifices there is a yearly reminder of sins.', pt: 'Mas nesses sacrifícios cada ano se faz recordação dos pecados,' },
      { v: 4, en: 'For it is impossible that the blood of bulls and goats should take away sins.', pt: 'porque é impossível que o sangue de touros e de bodes tire pecados.' },
      { v: 5, en: 'Therefore when he comes into the world, he says, “Sacrifice and offering you didn’t desire, but you prepared a body for me.', pt: 'Pelo que, entrando no mundo, diz: Sacrifício e oferta não quiseste, mas um corpo me preparaste;' },
      { v: 6, en: 'You had no pleasure in whole burnt offerings and sacrifices for sin.', pt: 'não te deleitaste em holocaustos e oblações pelo pecado.' },
      { v: 7, en: 'Then I said, ‘Behold, I have come (in the scroll of the book it is written of me) to do your will, O God.’”', pt: 'Então eu disse: Eis-me aqui (no rol do livro está escrito de mim) para fazer, ó Deus, a tua vontade.' },
      { v: 8, en: 'Previously saying, “Sacrifices and offerings and whole burnt offerings and sacrifices for sin you didn’t desire, neither had pleasure in them” (those which are offered according to the law),', pt: 'Tendo dito acima: Sacrifício e ofertas e holocaustos e oblações pelo pecado não quiseste, nem neles te deleitaste (os quais se oferecem segundo a lei);' },
      { v: 9, en: 'then he has said, “Behold, I have come to do your will.” He takes away the first, that he may establish the second,', pt: 'agora disse: Eis-me aqui para fazer a tua vontade. Ele tira o primeiro, para estabelecer o segundo.' },
      { v: 10, en: 'by which will we have been sanctified through the offering of the body of Jesus Christ once for all.', pt: 'É nessa vontade dele que temos sido santificados pela oferta do corpo de Jesus Cristo, feita uma vez para sempre.' },
      { v: 11, en: 'Every priest indeed stands day by day serving and often offering the same sacrifices, which can never take away sins,', pt: 'Ora, todo sacerdote se apresenta dia após dia, ministrando e oferecendo muitas vezes os mesmos sacrifícios, que nunca podem tirar pecados;' },
      { v: 12, en: 'but he, when he had offered one sacrifice for sins forever, sat down on the right hand of God;', pt: 'mas este, havendo oferecido um único sacrifício pelos pecados, assentou-se para sempre à direita de Deus,' },
      { v: 13, en: 'from that time waiting until his enemies are made the footstool of his feet.', pt: 'daí por diante esperando, até que os seus inimigos sejam postos por escabelo de seus pés.' },
      { v: 14, en: 'For by one offering he has perfected forever those who are being sanctified.', pt: 'Pois com uma só oferta tem aperfeiçoado para sempre os que estão sendo santificados.' },
      { v: 15, en: 'The Holy Spirit also testifies to us, for after saying,', pt: 'E o Espírito Santo também no-lo testifica, porque depois de haver dito:' },
      { v: 16, en: '“This is the covenant that I will make with them: ‘After those days,’ says the Lord, ‘I will put my laws on their heart, I will also write them on their mind;’” then he says,', pt: 'Este é o pacto que farei com eles depois daqueles dias, diz o Senhor: Porei as minhas leis em seus corações, e as escreverei em seu entendimento; acrescenta:' },
      { v: 17, en: '“I will remember their sins and their iniquities no more.”', pt: 'E não me lembrarei mais de seus pecados e de suas iniqüidades.' },
      { v: 18, en: 'Now where remission of these is, there is no more offering for sin.', pt: 'Ora, onde há remissão destes, não há mais oferta pelo pecado.' },
      { v: 19, en: 'Having therefore, brothers, boldness to enter into the holy place by the blood of Jesus,', pt: 'Tendo pois, irmãos, ousadia para entrarmos no santíssimo lugar, pelo sangue de Jesus,' },
      { v: 20, en: 'by the way which he dedicated for us, a new and living way, through the veil, that is to say, his flesh;', pt: 'pelo caminho que ele nos inaugurou, caminho novo e vivo, através do véu, isto é, da sua carne,' },
      { v: 21, en: 'and having a great priest over God’s house,', pt: 'e tendo um grande sacerdote sobre a casa de Deus,' },
      { v: 22, en: 'let’s draw near with a true heart in fullness of faith, having our hearts sprinkled from an evil conscience, and having our body washed with pure water,', pt: 'cheguemo-nos com verdadeiro coração, em inteira certeza de fé; tendo o coração purificado da má consciência, e o corpo lavado com água limpa,' },
      { v: 23, en: 'let us hold fast the confession of our hope without wavering; for he who promised is faithful.', pt: 'retenhamos inabalável a confissão da nossa esperança, porque fiel é aquele que fez a promessa;' },
      { v: 24, en: 'Let us consider how to provoke one another to love and good works,', pt: 'e consideremo-nos uns aos outros, para nos estimularmos ao amor e às boas obras,' },
      { v: 25, en: 'not forsaking our own assembling together, as the custom of some is, but exhorting one another; and so much the more, as you see the Day approaching.', pt: 'não abandonando a nossa congregação, como é costume de alguns, antes admoestando-nos uns aos outros; e tanto mais, quanto vedes que se vai aproximando aquele dia.' },
      { v: 26, en: 'For if we sin willfully after we have received the knowledge of the truth, there remains no more a sacrifice for sins,', pt: 'Porque se voluntariamente continuarmos no pecado, depois de termos recebido o pleno conhecimento da verdade, já não resta mais sacrifício pelos pecados,' },
      { v: 27, en: 'but a certain fearful expectation of judgment, and a fierceness of fire which will devour the adversaries.', pt: 'mas uma expectação terrível de juízo, e um ardor de fogo que há de devorar os adversários.' },
      { v: 28, en: 'A man who disregards Moses’ law dies without compassion on the word of two or three witnesses.', pt: 'Havendo alguém rejeitado a lei de Moisés, morre sem misericórdia, pela palavra de duas ou três testemunhas;' },
      { v: 29, en: 'How much worse punishment do you think he will be judged worthy of who has trodden under foot the Son of God, and has counted the blood of the covenant with which he was sanctified an unholy thing, and has insulted the Spirit of grace?', pt: 'de quanto maior castigo cuidais vós será julgado merecedor aquele que pisar o Filho de Deus, e tiver por profano o sangue do pacto, com que foi santificado, e ultrajar ao Espírito da graça?' },
      { v: 30, en: 'For we know him who said, “Vengeance belongs to me,” says the Lord, “I will repay.” Again, “The Lord will judge his people.”', pt: 'Pois conhecemos aquele que disse: Minha é a vingança, eu retribuirei. E outra vez: O Senhor julgará o seu povo.' },
      { v: 31, en: 'It is a fearful thing to fall into the hands of the living God.', pt: 'Horrenda coisa é cair nas mãos do Deus vivo.' },
      { v: 32, en: 'But remember the former days, in which, after you were enlightened, you endured a great struggle with sufferings;', pt: 'Lembrai-vos, porém, dos dias passados, em que, depois de serdes iluminados, suportastes grande combate de aflições;' },
      { v: 33, en: 'partly, being exposed to both reproaches and oppressions; and partly, becoming partakers with those who were treated so.', pt: 'pois por um lado fostes feitos espetáculo tanto por vitupérios como por tribulações, e por outro vos tornastes companheiros dos que assim foram tratados.' },
      { v: 34, en: 'For you both had compassion on me in my chains, and joyfully accepted the plundering of your possessions, knowing that you have for yourselves a better possession and an enduring one in the heavens.', pt: 'Pois não só vos compadecestes dos que estavam nas prisões, mas também com gozo aceitastes a espoliação dos vossos bens, sabendo que vós tendes uma possessão melhor e permanente.' },
      { v: 35, en: 'Therefore don’t throw away your boldness, which has a great reward.', pt: 'Não lanceis fora, pois, a vossa confiança, que tem uma grande recompensa.' },
      { v: 36, en: 'For you need endurance so that, having done the will of God, you may receive the promise.', pt: 'Porque necessitais de perseverança, para que, depois de haverdes feito a vontade de Deus, alcanceis a promessa.' },
      { v: 37, en: '“In a very little while, he who comes will come, and will not wait.', pt: 'Pois ainda em bem pouco tempo aquele que há de vir virá, e não tardará.' },
      { v: 38, en: 'But the righteous will live by faith. If he shrinks back, my soul has no pleasure in him.”', pt: 'Mas o meu justo viverá da fé; e se ele recuar, a minha alma não tem prazer nele.' },
      { v: 39, en: 'But we are not of those who shrink back to destruction, but of those who have faith to the saving of the soul.', pt: 'Nós, porém, não somos daqueles que recuam para a perdição, mas daqueles que crêem para a conservação da alma.' },
    ],
    11: [
      { v: 1, en: 'Now faith is assurance of things hoped for, proof of things not seen.', pt: 'Ora, a fé é o firme fundamento das coisas que se esperam, e a prova das coisas que não se vêem.' },
      { v: 2, en: 'For by this, the elders obtained testimony.', pt: 'Porque por ela os antigos alcançaram bom testemunho.' },
      { v: 3, en: 'By faith, we understand that the universe has been framed by the word of God, so that what is seen has not been made out of things which are visible.', pt: 'Pela fé entendemos que os mundos foram criados pela palavra de Deus; de modo que o visível não foi feito daquilo que se vê.' },
      { v: 4, en: 'By faith, Abel offered to God a more excellent sacrifice than Cain, through which he had testimony given to him that he was righteous, God testifying with respect to his gifts; and through it he, being dead, still speaks.', pt: 'Pela fé Abel ofereceu a Deus mais excelente sacrifício que Caim, pelo qual alcançou testemunho de que era justo, dando Deus testemunho das suas oferendas, e por meio dela depois de morto, ainda fala.' },
      { v: 5, en: 'By faith, Enoch was taken away, so that he wouldn’t see death, and he was not found, because God translated him. For he has had testimony given to him that before his translation he had been well pleasing to God.', pt: 'Pela fé Enoque foi trasladado para não ver a morte; e não foi achado, porque Deus o trasladara; pois antes da sua trasladação alcançou testemunho de que agradara a Deus.' },
      { v: 6, en: 'Without faith it is impossible to be well pleasing to him, for he who comes to God must believe that he exists, and that he is a rewarder of those who seek him.', pt: 'Ora, sem fé é impossível agradar a Deus; porque é necessário que aquele que se aproxima de Deus creia que ele existe, e que é galardoador dos que o buscam.' },
      { v: 7, en: 'By faith, Noah, being warned about things not yet seen, moved with godly fear, prepared a ship for the saving of his house, through which he condemned the world, and became heir of the righteousness which is according to faith.', pt: 'Pela fé Noé, divinamente avisado das coisas que ainda não se viam, sendo temente a Deus, preparou uma arca para o salvamento da sua família; e por esta fé condenou o mundo, e tornou-se herdeiro da justiça que é segundo a fé.' },
      { v: 8, en: 'By faith, Abraham, when he was called, obeyed to go out to the place which he was to receive for an inheritance. He went out, not knowing where he went.', pt: 'Pela fé Abraão, sendo chamado, obedeceu, saindo para um lugar que havia de receber por herança; e saiu, sem saber para onde ia.' },
      { v: 9, en: 'By faith, he lived as an alien in the land of promise, as in a land not his own, dwelling in tents, with Isaac and Jacob, the heirs with him of the same promise.', pt: 'Pela fé peregrinou na terra da promessa, como em terra alheia, habitando em tendas com Isaque e Jacó, herdeiros com ele da mesma promessa;' },
      { v: 10, en: 'For he looked for the city which has the foundations, whose builder and maker is God.', pt: 'porque esperava a cidade que tem os fundamentos, da qual o arquiteto e edificador é Deus.' },
      { v: 11, en: 'By faith, even Sarah herself received power to conceive, and she bore a child when she was past age, since she counted him faithful who had promised.', pt: 'Pela fé, até a própria Sara recebeu a virtude de conceber um filho, mesmo fora da idade, porquanto teve por fiel aquele que lho havia prometido.' },
      { v: 12, en: 'Therefore as many as the stars of the sky in multitude, and as innumerable as the sand which is by the sea shore, were fathered by one man, and him as good as dead.', pt: 'Pelo que também de um, e esse já amortecido, descenderam tantos, em multidão, como as estrelas do céu, e como a areia inumerável que está na praia do mar.' },
      { v: 13, en: 'These all died in faith, not having received the promises, but having seen them and embraced them from afar, and having confessed that they were strangers and pilgrims on the earth.', pt: 'Todos estes morreram na fé, sem terem alcançado as promessas; mas tendo-as visto e saudado, de longe, confessaram que eram estrangeiros e peregrinos na terra.' },
      { v: 14, en: 'For those who say such things make it clear that they are seeking a country of their own.', pt: 'Ora, os que tais coisas dizem, mostram que estão buscando uma pátria.' },
      { v: 15, en: 'If indeed they had been thinking of that country from which they went out, they would have had enough time to return.', pt: 'E se, na verdade, se lembrassem daquela donde haviam saído, teriam oportunidade de voltar.' },
      { v: 16, en: 'But now they desire a better country, that is, a heavenly one. Therefore God is not ashamed of them, to be called their God, for he has prepared a city for them.', pt: 'Mas agora desejam uma pátria melhor, isto é, a celestial. Pelo que também Deus não se envergonha deles, de ser chamado seu Deus, porque já lhes preparou uma cidade.' },
      { v: 17, en: 'By faith, Abraham, being tested, offered up Isaac. Yes, he who had gladly received the promises was offering up his one and only son,', pt: 'Pela fé Abraão, sendo provado, ofereceu Isaque; sim, ia oferecendo o seu unigênito aquele que recebera as promessas,' },
      { v: 18, en: 'to whom it was said, “your offspring will be accounted as from Isaac”;', pt: 'e a quem se havia dito: Em Isaque será chamada a tua descendência,' },
      { v: 19, en: 'concluding that God is able to raise up even from the dead. Figuratively speaking, he also did receive him back from the dead.', pt: 'julgando que Deus era poderoso para até dos mortos o ressuscitar; e daí também em figura o recobrou.' },
      { v: 20, en: 'By faith, Isaac blessed Jacob and Esau, even concerning things to come.', pt: 'Pela fé Isaque abençoou Jacó e a Esaú, no tocante às coisas futuras.' },
      { v: 21, en: 'By faith, Jacob, when he was dying, blessed each of the sons of Joseph, and worshiped, leaning on the top of his staff.', pt: 'Pela fé Jacó, quando estava para morrer, abençoou cada um dos filhos de José, e adorou, inclinado sobre a extremidade do seu bordão.' },
      { v: 22, en: 'By faith, Joseph, when his end was near, made mention of the departure of the children of Israel; and gave instructions concerning his bones.', pt: 'Pela fé José, estando próximo o seu fim, fez menção da saída dos filhos de Israel, e deu ordem acerca de seus ossos.' },
      { v: 23, en: 'By faith, Moses, when he was born, was hidden for three months by his parents, because they saw that he was a beautiful child, and they were not afraid of the king’s commandment.', pt: 'Pela fé Moisés, logo ao nascer, foi escondido por seus pais durante três meses, porque viram que o menino era formoso; e não temeram o decreto do rei.' },
      { v: 24, en: 'By faith, Moses, when he had grown up, refused to be called the son of Pharaoh’s daughter,', pt: 'Pela fé Moisés, sendo já homem, recusou ser chamado filho da filha de Faraó,' },
      { v: 25, en: 'choosing rather to share ill treatment with God’s people, than to enjoy the pleasures of sin for a time;', pt: 'escolhendo antes ser maltratado com o povo de Deus do que ter por algum tempo o gozo do pecado,' },
      { v: 26, en: 'accounting the reproach of Christ greater riches than the treasures of Egypt; for he looked to the reward.', pt: 'tendo por maiores riquezas o opróbrio de Cristo do que os tesouros do Egito; porque tinha em vista a recompensa.' },
      { v: 27, en: 'By faith, he left Egypt, not fearing the wrath of the king; for he endured, as seeing him who is invisible.', pt: 'Pela fé deixou o Egito, não temendo a ira do rei; porque ficou firme, como quem vê aquele que é invisível.' },
      { v: 28, en: 'By faith, he kept the Passover, and the sprinkling of the blood, that the destroyer of the firstborn should not touch them.', pt: 'Pela fé celebrou a páscoa e a aspersão do sangue, para que o destruidor dos primogênitos não lhes tocasse.' },
      { v: 29, en: 'By faith, they passed through the Red Sea as on dry land. When the Egyptians tried to do so, they were swallowed up.', pt: 'Pela fé os israelitas atravessaram o Mar Vermelho, como por terra seca; e tentando isso os egípcios, foram afogados.' },
      { v: 30, en: 'By faith, the walls of Jericho fell down, after they had been encircled for seven days.', pt: 'Pela fé caíram os muros de Jericó, depois de rodeados por sete dias.' },
      { v: 31, en: 'By faith, Rahab the prostitute, didn’t perish with those who were disobedient, having received the spies in peace.', pt: 'Pela fé Raabe, a meretriz, não pereceu com os desobedientes, tendo acolhido em paz os espias.' },
      { v: 32, en: 'What more shall I say? For the time would fail me if I told of Gideon, Barak, Samson, Jephthah, David, Samuel, and the prophets;', pt: 'E que mais direi? Pois me faltará o tempo, se eu contar de Gideão, de Baraque, de Sansão, de Jefté, de Davi, de Samuel e dos profetas;' },
      { v: 33, en: 'who, through faith subdued kingdoms, worked out righteousness, obtained promises, stopped the mouths of lions,', pt: 'os quais por meio da fé venceram reinos, praticaram a justiça, alcançaram promessas, fecharam a boca dos leões,' },
      { v: 34, en: 'quenched the power of fire, escaped the edge of the sword, from weakness were made strong, grew mighty in war, and caused foreign armies to flee.', pt: 'apagaram a força do fogo, escaparam ao fio da espada, da fraqueza tiraram forças, tornaram-se poderosos na guerra, puseram em fuga exércitos estrangeiros.' },
      { v: 35, en: 'Women received their dead by resurrection. Others were tortured, not accepting their deliverance, that they might obtain a better resurrection.', pt: 'As mulheres receberam pela ressurreição os seus mortos; uns foram torturados, não aceitando o seu livramento, para alcançarem uma melhor ressurreição;' },
      { v: 36, en: 'Others were tried by mocking and scourging, yes, moreover by bonds and imprisonment.', pt: 'e outros experimentaram escárnios e açoites, e ainda cadeias e prisões.' },
      { v: 37, en: 'They were stoned. They were sawn apart. They were tempted. They were slain with the sword. They went around in sheep skins and in goat skins; being destitute, afflicted, ill-treated', pt: 'Foram apedrejados e tentados; foram serrados ao meio; morreram ao fio da espada; andaram vestidos de peles de ovelhas e de cabras, necessitados, aflitos e maltratados' },
      { v: 38, en: '(of whom the world was not worthy), wandering in deserts, mountains, caves, and the holes of the earth.', pt: '(dos quais o mundo não era digno), errantes pelos desertos e montes, e pelas covas e cavernas da terra.' },
      { v: 39, en: 'These all, having had testimony given to them through their faith, didn’t receive the promise,', pt: 'E todos estes, embora tendo recebido bom testemunho pela fé, contudo não alcançaram a promessa;' },
      { v: 40, en: 'God having provided some better thing concerning us, so that apart from us they should not be made perfect.', pt: 'visto que Deus provera alguma coisa melhor a nosso respeito, para que eles, sem nós, não fossem aperfeiçoados.' },
    ],
    12: [
      { v: 1, en: 'Therefore let us also, seeing we are surrounded by so great a cloud of witnesses, lay aside every weight and the sin which so easily entangles us, and let us run with perseverance the race that is set before us,', pt: 'Portanto, nós também, pois estamos rodeados de tão grande nuvem de testemunhas, deixemos todo embaraço, e o pecado que tão de perto nos rodeia, e corramos com perseverança a carreira que nos está proposta,' },
      { v: 2, en: 'looking to Jesus, the author and perfecter of faith, who for the joy that was set before him endured the cross, despising its shame, and has sat down at the right hand of the throne of God.', pt: 'fitando os olhos em Jesus, autor e consumador da nossa fé, o qual, pelo gozo que lhe está proposto, suportou a cruz, desprezando a ignomínia, e está assentado à direita do trono de Deus.' },
      { v: 3, en: 'For consider him who has endured such contradiction of sinners against himself, that you don’t grow weary, fainting in your souls.', pt: 'Considerai, pois aquele que suportou tal contradição dos pecadores contra si mesmo, para que não vos canseis, desfalecendo em vossas almas.' },
      { v: 4, en: 'You have not yet resisted to blood, striving against sin;', pt: 'Ainda não resististes até o sangue, combatendo contra o pecado;' },
      { v: 5, en: 'and you have forgotten the exhortation which reasons with you as with children, “My son, don’t take lightly the chastening of the Lord, nor faint when you are reproved by him;', pt: 'e já vos esquecestes da exortação que vos admoesta como a filhos: Filho meu, não desprezes a correção do Senhor, nem te desanimes quando por ele és repreendido;' },
      { v: 6, en: 'For whom the Lord loves, he chastens, and scourges every son whom he receives.”', pt: 'pois o Senhor corrige ao que ama, e açoita a todo o que recebe por filho.' },
      { v: 7, en: 'It is for discipline that you endure. God deals with you as with children, for what son is there whom his father doesn’t discipline?', pt: 'É para disciplina que sofreis; Deus vos trata como a filhos; pois qual é o filho a quem o pai não corrija?' },
      { v: 8, en: 'But if you are without discipline, of which all have been made partakers, then are you illegitimate, and not children.', pt: 'Mas, se estais sem disciplina, da qual todos se têm tornado participantes, sois então bastardos, e não filhos.' },
      { v: 9, en: 'Furthermore, we had the fathers of our flesh to chasten us, and we paid them respect. Shall we not much rather be in subjection to the Father of spirits, and live?', pt: 'Além disto, tivemos nossos pais segundo a carne, para nos corrigirem, e os olhavamos com respeito; não nos sujeitaremos muito mais ao Pai dos espíritos, e viveremos?' },
      { v: 10, en: 'For they indeed, for a few days, punished us as seemed good to them; but he for our profit, that we may be partakers of his holiness.', pt: 'Pois aqueles por pouco tempo nos corrigiam como bem lhes parecia, mas este, para nosso proveito, para sermos participantes da sua santidade.' },
      { v: 11, en: 'All chastening seems for the present to be not joyous but grievous; yet afterward it yields the peaceful fruit of righteousness to those who have been exercised thereby.', pt: 'Na verdade, nenhuma correção parece no momento ser motivo de gozo, porém de tristeza; mas depois produz um fruto pacífico de justiça nos que por ele têm sido exercitados.' },
      { v: 12, en: 'Therefore lift up the hands that hang down and the feeble knees,', pt: 'Portanto levantai as mãos cansadas, e os joelhos vacilantes,' },
      { v: 13, en: 'and make straight paths for your feet, so what is lame may not be dislocated, but rather be healed.', pt: 'e fazei veredas direitas para os vossos pés, para que o que é manco não se desvie, antes seja curado.' },
      { v: 14, en: 'Follow after peace with all men, and the sanctification without which no man will see the Lord,', pt: 'Segui a paz com todos, e a santificação, sem a qual ninguém verá o Senhor,' },
      { v: 15, en: 'looking carefully lest there be any man who falls short of the grace of God; lest any root of bitterness springing up trouble you, and many be defiled by it;', pt: 'tendo cuidado de que ninguém se prive da graça de Deus, e de que nenhuma raiz de amargura, brotando, vos perturbe, e por ela muitos se contaminem;' },
      { v: 16, en: 'lest there be any sexually immoral person, or profane person, like Esau, who sold his birthright for one meal.', pt: 'e ninguém seja devasso, ou profano como Esaú, que por uma simples refeição vendeu o seu direito de primogenitura.' },
      { v: 17, en: 'For you know that even when he afterward desired to inherit the blessing, he was rejected, for he found no place for a change of mind though he sought it diligently with tears.', pt: 'Porque bem sabeis que, querendo ele ainda depois herdar a bênção, foi rejeitado; porque não achou lugar de arrependimento, ainda que o buscou diligentemente com lágrimas.' },
      { v: 18, en: 'For you have not come to a mountain that might be touched, and that burned with fire, and to blackness, darkness, storm,', pt: 'Pois não tendes chegado ao monte palpável, aceso em fogo, e à escuridão, e às trevas, e à tempestade,' },
      { v: 19, en: 'the sound of a trumpet, and the voice of words; which those who heard it begged that not one more word should be spoken to them,', pt: 'e ao sonido da trombeta, e à voz das palavras, a qual os que a ouviram rogaram que não se lhes falasse mais;' },
      { v: 20, en: 'for they could not stand that which was commanded, “If even an animal touches the mountain, it shall be stoned” ;', pt: 'porque não podiam suportar o que se lhes mandava: Se até um animal tocar o monte, será apedrejado.' },
      { v: 21, en: 'and so fearful was the appearance that Moses said, “I am terrified and trembling.”', pt: 'E tão terrível era a visão, que Moisés disse: Estou todo aterrorizado e trêmulo.' },
      { v: 22, en: 'But you have come to Mount Zion, and to the city of the living God, the heavenly Jerusalem, and to innumerable multitudes of angels,', pt: 'Mas tendes chegado ao Monte Sião, e à cidade do Deus vivo, à Jerusalém celestial, a miríades de anjos;' },
      { v: 23, en: 'to the festal gathering and assembly of the firstborn who are enrolled in heaven, to God the Judge of all, to the spirits of just men made perfect,', pt: 'à universal assembléia e igreja dos primogênitos inscritos nos céus, e a Deus, o juiz de todos, e aos espíritos dos justos aperfeiçoados;' },
      { v: 24, en: 'to Jesus, the mediator of a new covenant, and to the blood of sprinkling that speaks better than that of Abel.', pt: 'e a Jesus, o mediador de um novo pacto, e ao sangue da aspersão, que fala melhor do que o de Abel.' },
      { v: 25, en: 'See that you don’t refuse him who speaks. For if they didn’t escape when they refused him who warned on the earth, how much more will we not escape who turn away from him who warns from heaven,', pt: 'Vede que não rejeiteis ao que fala; porque, se não escaparam aqueles quando rejeitaram o que sobre a terra os advertia, muito menos escaparemos nós, se nos desviarmos daquele que nos adverte lá dos céus;' },
      { v: 26, en: 'whose voice shook the earth then, but now he has promised, saying, “Yet once more I will shake not only the earth, but also the heavens.”', pt: 'a voz do qual abalou então a terra; mas agora tem ele prometido, dizendo: Ainda uma vez hei de abalar não só a terra, mas também o céu.' },
      { v: 27, en: 'This phrase, “Yet once more”, signifies the removing of those things that are shaken, as of things that have been made, that those things which are not shaken may remain.', pt: 'Ora, esta palavra - Ainda uma vez - significa a remoção das coisas abaláveis, como coisas criadas, para que permaneçam as coisas inabaláveis.' },
      { v: 28, en: 'Therefore, receiving a Kingdom that can’t be shaken, let us have grace, through which we serve God acceptably, with reverence and awe,', pt: 'Pelo que, recebendo nós um reino que não pode ser abalado, retenhamos a graça, pela qual sirvamos a Deus agradavelmente, com reverência e temor;' },
      { v: 29, en: 'for our God is a consuming fire.', pt: 'pois o nosso Deus é um fogo consumidor.' },
    ],
    13: [
      { v: 1, en: 'Let brotherly love continue.', pt: 'Permaneça o amor fraternal.' },
      { v: 2, en: 'Don’t forget to show hospitality to strangers, for in doing so, some have entertained angels without knowing it.', pt: 'Não vos esqueçais da hospitalidade, porque por ela alguns, sem o saberem, hospedaram anjos.' },
      { v: 3, en: 'Remember those who are in bonds, as bound with them; and those who are ill-treated, since you are also in the body.', pt: 'Lembrai-vos dos presos, como se estivésseis presos com eles, e dos maltratados, como sendo-o vós mesmos também no corpo.' },
      { v: 4, en: 'Let marriage be held in honor among all, and let the bed be undefiled: but God will judge the sexually immoral and adulterers.', pt: 'Honrado seja entre todos o matrimônio e o leito sem mácula; pois aos devassos e adúlteros, Deus os julgará.' },
      { v: 5, en: 'Be free from the love of money, content with such things as you have, for he has said, “I will in no way leave you, neither will I in any way forsake you.”', pt: 'Seja a vossa vida isenta de ganância, contentando-vos com o que tendes; porque ele mesmo disse: Não te deixarei, nem te desampararei.' },
      { v: 6, en: 'So that with good courage we say, “The Lord is my helper. I will not fear. What can man do to me?”', pt: 'De modo que com plena confiança digamos: O Senhor é quem me ajuda, não temerei; que me fará o homem?' },
      { v: 7, en: 'Remember your leaders, men who spoke to you the word of God, and considering the results of their conduct, imitate their faith.', pt: 'Lembrai-vos dos vossos guias, os quais vos falaram a palavra de Deus, e, atentando para o êxito da sua carreira, imitai-lhes a fé.' },
      { v: 8, en: 'Jesus Christ is the same yesterday, today, and forever.', pt: 'Jesus Cristo é o mesmo, ontem, e hoje, e eternamente.' },
      { v: 9, en: 'Don’t be carried away by various and strange teachings, for it is good that the heart be established by grace, not by food, through which those who were so occupied were not benefited.', pt: 'Não vos deixeis levar por doutrinas várias e estranhas; porque bom é que o coração se fortifique com a graça, e não com alimentos, que não trouxeram proveito algum aos que com eles se preocuparam.' },
      { v: 10, en: 'We have an altar from which those who serve the holy tabernacle have no right to eat.', pt: 'Temos um altar, do qual não têm direito de comer os que servem ao tabernáculo.' },
      { v: 11, en: 'For the bodies of those animals, whose blood is brought into the holy place by the high priest as an offering for sin, are burned outside of the camp.', pt: 'Porque os corpos dos animais, cujo sangue é trazido para dentro do santo lugar pelo sumo sacerdote como oferta pelo pecado, são queimados fora do arraial.' },
      { v: 12, en: 'Therefore Jesus also, that he might sanctify the people through his own blood, suffered outside of the gate.', pt: 'Por isso também Jesus, para santificar o povo pelo seu próprio sangue, sofreu fora da porta.' },
      { v: 13, en: 'Let us therefore go out to him outside of the camp, bearing his reproach.', pt: 'Saiamos pois a ele fora do arraial, levando o seu opróbrio.' },
      { v: 14, en: 'For we don’t have here an enduring city, but we seek that which is to come.', pt: 'Porque não temos aqui cidade permanente, mas buscamos a vindoura.' },
      { v: 15, en: 'Through him, then, let us offer up a sacrifice of praise to God continually, that is, the fruit of lips which proclaim allegiance to his name.', pt: 'Por ele, pois, ofereçamos sempre a Deus sacrifício de louvor, isto é, o fruto dos lábios que confessam o seu nome.' },
      { v: 16, en: 'But don’t forget to be doing good and sharing, for with such sacrifices God is well pleased.', pt: 'Mas não vos esqueçais de fazer o bem e de repartir com outros, porque com tais sacrifícios Deus se agrada.' },
      { v: 17, en: 'Obey your leaders and submit to them, for they watch on behalf of your souls, as those who will give account, that they may do this with joy, and not with groaning, for that would be unprofitable for you.', pt: 'Obedecei a vossos guias, sendo-lhes submissos; porque velam por vossas almas como quem há de prestar contas delas; para que o façam com alegria e não gemendo, porque isso não vos seria útil.' },
      { v: 18, en: 'Pray for us, for we are persuaded that we have a good conscience, desiring to live honorably in all things.', pt: 'Orai por nós, porque estamos persuadidos de que temos boa consciência, sendo desejosos de, em tudo, portar-nos corretamente.' },
      { v: 19, en: 'I strongly urge you to do this, that I may be restored to you sooner.', pt: 'E com instância vos exorto a que o façais, para que eu mais depressa vos seja restituído.' },
      { v: 20, en: 'Now may the God of peace, who brought again from the dead the great shepherd of the sheep with the blood of an eternal covenant, our Lord Jesus,', pt: 'Ora, o Deus de paz, que pelo sangue do pacto eterno tornou a trazer dentre os mortos a nosso Senhor Jesus, grande pastor das ovelhas,' },
      { v: 21, en: 'make you complete in every good work to do his will, working in you that which is well pleasing in his sight, through Jesus Christ, to whom be the glory forever and ever. Amen.', pt: 'vos aperfeiçoe em toda boa obra, para fazerdes a sua vontade, operando em nós o que perante ele é agradável, por meio de Jesus Cristo, ao qual seja glória para todo o sempre. Amém.' },
      { v: 22, en: 'But I exhort you, brothers, endure the word of exhortation; for I have written to you in few words.', pt: 'Rogo-vos, porém, irmãos, que suporteis estas palavras de exortação, pois vos escrevi em poucas palavras.' },
      { v: 23, en: 'Know that our brother Timothy has been freed, with whom, if he comes shortly, I will see you.', pt: 'Sabei que o irmão Timóteo já está solto, com o qual, se ele vier brevemente, vos verei.' },
      { v: 24, en: 'Greet all of your leaders and all the saints. The Italians greet you.', pt: 'Saudai a todos os vossos guias e a todos os santos. Os de Itália vos saúdam.' },
      { v: 25, en: 'Grace be with you all. Amen.', pt: 'A graça seja com todos vós.' },
    ],
  },
};

export default book;
